mapper.select:
select sl.id, sl.type, sl.username, sl.operation, sl.method, sl.params, sl.time, sl.ip, sl.create_date as create_date from sys_log sl
sl.deleted = 1
and sl.username = #{username}
and sl.operation = #{operation}
and sl.type = #{type}
and sl.create_date between #{startTime} and #{endTime}

select sl.id, sl.type, sl.username, sl.operation, sl.method, sl.params, sl.time, sl.ip, sl.create_date as create_date from sys_log sl
and sl.username = #{username}
and sd.name = #{centerName}
and sl.operation = #{operation}
and CONCAT(sl.username,sd.name) LIKE CONCAT('%',#{keywords},'%')
and sl.type = #{type}
and sl.create_date between #{startTime} and #{endTime}
